css:
.loader {
  display: inline-flex;
  gap: 7px;
  color: #6366f1;
}
.loader b {
  width: 11px;
  height: 11px;
  border-radius: 999px;
  background: currentColor;
  transform-origin: center;
  animation: elastic 0.9s ease-in-out infinite;
}
.loader b:nth-child(2) { animation-delay: 0.12s; }
.loader b:nth-child(3) { animation-delay: 0.24s; }
@keyframes elastic {
  0%, 100% { transform: scaleY(1); opacity: 0.45; }
  45% { transform: scaleY(2.1); opacity: 1; }
}
